examples.call:
main.sh src/core/query/modifiers/added.ts replace-block "): Modifier<ExtractTraits<T>," "{
    const traits: Trait[] = [];
    for (const input of inputs) {
        if (isAspect(input)) {
            for (const t of input.traits) {
                traits.push(t);
            }
        } else if (isRelation(input)) {
            traits.push(input[$internal].trait);
        } else {
            traits.push(input as Trait);
        }
    }
    return createModifier(`added-${id}`, id, traits);
}"

cat << 'PYEOF' | main.sh src/api.py stdin-replace-pyblock "def format_string"
def format_string(source_string: str, mode: Mode) -> str:
    """Formats SQL string."""
    ddl_result = _format_ddl_string(source_string, mode.line_length)
    if ddl_result is not None:
        return ddl_result
    analyzer = mode.dialect.initialize_analyzer(line_length=mode.line_length)
    return analyzer.format(source_string)
PYEOF
